def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.sqrt(cap) * 30 + np.log1p(cap*2) * 18
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.05)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 45 * np.cos(cap * 2)
            else:
                base_priority -= 50 * usage
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.75) * 25 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 9):
                fluctuation += np.cos(usage * np.pi * (j ** 1.25)) * 30 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 17)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3)**1.7
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 0.6:
                base_priority += 40 * np.sin(cap * 3.5)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2)**2.2
            for m in range(1, 17):
                pwr = usage ** m
                if pwr < 0.5:
                    fluctuation += pwr * 28 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 14 and usage > 2.7:
                        fluctuation += 18
            if cap % 2.7 < 0.7:
                base_priority += 38 * np.cos(cap * 2.7)
        elif 1 < usage <= 2:
            base_priority += 950 * (usage - 1) ** 3.5
            for n in range(1, 20):
                power = usage ** n
                if power < 0.7:
                    fluctuation += power * 27 / n
                    if n % 4 == 3:
                        fluctuation -= n * 1.8
                else:
                    fluctuation += (1 - power) * 13 / (n + 1)
                    if n == 17 and usage > 1.8:
                        fluctuation += 20
            if cap % 1.7 < 0.4:
                base_priority += 33 * np.sin(cap * 2.5)
        elif 0.7 < usage <= 1:
            base_priority += 140 * (1 - usage)**1.5
            for o in range(1, 13):
                power = usage ** o
                fluctuation += (np.tanh(power * np.pi / 3) - 0.35) * 14 / o
                if usage < 0.09 * o:
                    fluctuation -= 10 * o
            if cap < 0.1:
                base_priority += np.sqrt(cap) * 320
            elif cap < 1.0:
                base_priority += np.log1p(cap * 25) * 38
            else:
                base_priority += (cap % 7) * 24
        elif 0.25 < usage <= 0.7:
            base_priority += 280 * (1 - usage) ** 2.5
            for p in range(1, 20):
                power = usage ** p
                fluctuation += (np.sin(power * np.pi / 5) - 0.3) * 15 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.log1p(cap) * 400
            elif cap < 1.2:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
        else:
            base_priority += 350 * (1 - usage) ** 3
            for q in range(1, 25):
                pow_u = usage ** q
                fluctuation += (np.sin(pow_u * np.pi / 7) - 0.2) * 17 / q
                if usage < 0.01 * q:
                    fluctuation -= 16 * q
            if cap < 0.01:
                base_priority += np.sqrt(cap + 0.01) * 350
            elif cap < 1.5:
                base_priority += np.log1p(cap * 35) * 60
            else:
                base_priority += (cap % 9) * 40
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 55
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1500) % (s + 6) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.95:
                priority += 110
                for u in range(1, 6):
                    priority += u * 15
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 17 == 0:
            proximity += 20
        if int(cap * 1100) % 29 == 0:
            proximity -= 15
        if int(cap * 210) % 11 == 0:
            proximity += 18
        for v in range(1, 11):
            diff = abs(usage - v / 11)
            if diff < 0.015:
                proximity += 25 / v
            elif diff < 0.04:
                proximity += 15 / v
            else:
                proximity -= 5 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1800) % (w + 12)
            if mod_chk == 1:
                proximity += w * 7
            elif mod_chk == 4:
                proximity -= w * 6
        for x in range(1, 6):
            mod_chk2 = int(usage * 1700) % (x + 7)
            if mod_chk2 == 1:
                proximity += 12 * x
            elif mod_chk2 == 4:
                proximity -= 9 * x
        priority += proximity
        if usage < 0.004:
            for y in range(1, 9):
                priority -= y * 15
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 14
        if cap > 3.0:
            if cap % 1.2 < 0.07:
                priority += 50
            if (int(cap * 2700) % 29 == 0) and (usage > 0.75):
                priority += 80
            for aa in range(1, 7):
                if (int(cap * 650) % (aa + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
